1	function countLiveNeighbors(
2	  livingCells: Set<string>,
3	  x: number,
4	  y: number
5	): number {
6	  let count = 0;
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      if (livingCells.has(`${x + dx},${y + dy}`)) count++;
11	    }
12	  }
13	  return count;
14	}
15	
16	function survives(liveNeighborCount: number): boolean {
17	  return liveNeighborCount === 2 || liveNeighborCount === 3;
18	}
19	
20	export function nextGeneration(livingCells: Set<string>): Set<string> {
21	  const survivors = new Set<string>();
22	  for (const cell of livingCells) {
23	    const [x, y] = cell.split(",").map(Number);
24	    if (survives(countLiveNeighbors(livingCells, x, y))) survivors.add(cell);
25	  }
26	  return survivors;
27	}
